@page "/privacy"
@attribute [ExcludeFromInteractiveRouting]
@using Microsoft.AspNetCore.Http
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (hasConsent)
{
    <div class="alert alert-success">
        ✓ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        You have not yet accepted our cookie policy.
    </div>
}

<h2>How We Use Cookies</h2>
<p>
    This site uses cookies to improve your experience. By continuing to browse the site,
    you agree to our use of cookies as described in this policy.
</p>

<h2>What Information We Collect</h2>
<p>
    We may collect information about your browsing activity on our site through the use of cookies
    and similar technologies. This includes pages visited, time spent on the site, and your preferences.
</p>

<h2>Your Rights</h2>
<p>
    You have the right to withdraw your consent at any time by clearing your browser cookies.
</p>

@code {
    private bool hasConsent;

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        hasConsent = httpContext?.Request.Cookies.ContainsKey("consent") == true;
    }
}

